PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:keyword "violence"@en
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:theme <http://publications.europa.eu/resource/authority/data-theme/JUST>
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?title
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:theme <http://publications.europa.eu/resource/authority/data-theme/JUST> ;
           dct:title ?title .
  FILTER(LANG(?title) = "en")
}
LIMIT 100

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:theme <http://publications.europa.eu/resource/authority/data-theme/JUST> ;
           dct:title ?title .
  FILTER(CONTAINS(LCASE(STR(?title)), "violence") || CONTAINS(LCASE(STR(?title)), "violenza") || CONTAINS(LCASE(STR(?title)), "violencia"))
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>

SELECT ?dataset ?theme
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:theme ?theme .
}
LIMIT 10

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:theme <http://eurovoc.europa.eu/2243>
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?title
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
}
LIMIT 5

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?title
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  FILTER(LANG(?title) = "en")
  FILTER(STR(?title) = "Violence against women")
}
LIMIT 5

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:keyword ?kw .
  FILTER(LANG(?kw) = "en")
  FILTER(CONTAINS(LCASE(STR(?kw)), "violence"))
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  FILTER(LANG(?title) = "en")
  FILTER(CONTAINS(LCASE(STR(?title)), "violence"))
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  FILTER(
    CONTAINS(LCASE(STR(?title)), "violence") ||
    CONTAINS(LCASE(STR(?title)), "violenza") ||
    CONTAINS(LCASE(STR(?title)), "violencia") ||
    CONTAINS(LCASE(STR(?title)), "gewalt")
  )
}

SELECT DISTINCT ?g (COUNT(*) AS ?n)
WHERE {
  GRAPH ?g { ?s a <http://www.w3.org/ns/dcat#Dataset> }
}
GROUP BY ?g
ORDER BY DESC(?n)

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  GRAPH <http://data.europa.eu/88u/graph/eudp> {
    ?dataset a dcat:Dataset ;
             dct:title ?title .
    FILTER(CONTAINS(LCASE(STR(?title)), "violence"))
  }
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX bif: <http://www.openlinksw.com/schemas/bif#>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  ?title bif:contains "'violence' OR 'violenza' OR 'violencia' OR 'gewalt' OR 'violência'"
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  FILTER(REGEX(STR(?title), "violenc|violenza|violencia|gewalt", "i"))
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset .
  {
    ?dataset dct:title ?title .
    FILTER(LANG(?title) IN ("it","en","fr","de","es"))
    FILTER(REGEX(STR(?title), "violenz|violence|violencia|violência|gewalt", "i"))
  }
  UNION
  {
    ?dataset dcat:keyword ?kw .
    FILTER(REGEX(STR(?kw), "violenz|violence|violencia|violência|gewalt", "i"))
  }
}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?dataset ?title
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title ;
           dct:spatial ?spatial .
  FILTER(LANG(?title) = "it")
  FILTER(CONTAINS(LCASE(?title), "toponimi"))
}
LIMIT 5

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcatap: <http://data.europa.eu/r5r/>

SELECT ?dataset ?title ?spatial
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title ;
           dct:spatial ?spatial .
  FILTER(LANG(?title) = "it")
  FILTER(CONTAINS(LCASE(?title), "geospazial"))
}
LIMIT 10

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT ?title ?format WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title ;
           dcat:distribution ?dist .
  ?dist dct:format ?format .
  FILTER(CONTAINS(LCASE(STR(?title)), "geografi"))
}
LIMIT 10

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?title ?publisher ?format WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title ;
           dct:publisher ?pub ;
           dcat:distribution ?dist .
  ?pub foaf:name ?publisher .
  ?dist dct:format ?format .
  FILTER(LANG(?title) = "it")
  FILTER(CONTAINS(LCASE(STR(?title)), "confini"))
  FILTER(CONTAINS(LCASE(STR(?format)), "geojson") || CONTAINS(LCASE(STR(?format)), "shp"))
}
LIMIT 10

